#include <iostream>

void reassignPointer(int* ptr, int* newAddr) {
    // Only modifies the local copy of the pointer
    ptr = newAddr;
}

int main() {
    int a = 10, b = 20;
    int* myPtr = &a;
    reassignPointer(myPtr, &b);
    // Logical issue: myPtr still points to 'a'
    std::cout << *myPtr << std::endl;
    return 0;
}

