#include <iostream>

class IntBuffer {
public:
    int* buffer;
    IntBuffer(int size) { buffer = new int[size]; }
    ~IntBuffer() { delete[] buffer; }
    // Missing copy constructor!
};

void processBuffer(IntBuffer temp) {
    temp.buffer[0] = 10;
}

int main() {
    IntBuffer myBuf(5);
    processBuffer(myBuf); // Shallow copy created and destroyed
    // UB: myBuf.buffer is now a dangling pointer. Double free upon exit.
    return 0;
}

output.optimized_code:
#include <iostream>
#include <algorithm>

class IntBuffer {
    int size_;
public:
    int* buffer;
    IntBuffer(int size) : size_(size) { buffer = new int[size_]; }
    ~IntBuffer() { delete[] buffer; }
    // Copy Constructor (Rule of Three)
    IntBuffer(const IntBuffer& other) : size_(other.size_) {
        buffer = new int[size_];
        std::copy(other.buffer, other.buffer + size_, buffer);
    }
};

void processBuffer(IntBuffer temp) {
    temp.buffer[0] = 10;
}

int main() {
    IntBuffer myBuf(5);
    processBuffer(myBuf);
    return 0;
}

